import React from 'react';
import { TrendingUp, TrendingDown, Minus } from 'lucide-react';

const StatCard = ({ title, value, icon: Icon, color, trend, trendValue, subtitle }) => {
  const getColorClasses = (color) => {
    const colors = {
      primary: {
        bg: 'from-blue-500 to-indigo-600',
        light: 'from-blue-100 to-indigo-100',
        text: 'text-blue-700 dark:text-blue-300'
      },
      secondary: {
        bg: 'from-gray-500 to-slate-600',
        light: 'from-gray-100 to-slate-100',
        text: 'text-gray-700 dark:text-gray-300'
      },
      success: {
        bg: 'from-green-500 to-emerald-600',
        light: 'from-green-100 to-emerald-100',
        text: 'text-green-700 dark:text-green-300'
      },
      warning: {
        bg: 'from-amber-500 to-orange-600',
        light: 'from-amber-100 to-orange-100',
        text: 'text-amber-700 dark:text-amber-300'
      },
      danger: {
        bg: 'from-red-500 to-rose-600',
        light: 'from-red-100 to-rose-100',
        text: 'text-red-700 dark:text-red-300'
      },
      emerald: {
        bg: 'from-emerald-500 to-teal-600',
        light: 'from-emerald-100 to-teal-100',
        text: 'text-emerald-700 dark:text-emerald-300'
      },
      violet: {
        bg: 'from-violet-500 to-purple-600',
        light: 'from-violet-100 to-purple-100',
        text: 'text-violet-700 dark:text-violet-300'
      },
      amber: {
        bg: 'from-amber-500 to-yellow-600',
        light: 'from-amber-100 to-yellow-100',
        text: 'text-amber-700 dark:text-amber-300'
      },
      blue: {
        bg: 'from-blue-500 to-cyan-600',
        light: 'from-blue-100 to-cyan-100',
        text: 'text-blue-700 dark:text-blue-300'
      }
    };
    return colors[color] || colors.primary;
  };

  const getTrendIcon = () => {
    if (trend === 'up') return <TrendingUp className="w-4 h-4 text-green-500" />;
    if (trend === 'down') return <TrendingDown className="w-4 h-4 text-red-500" />;
    return <Minus className="w-4 h-4 text-gray-500" />;
  };

  const colorClasses = getColorClasses(color);

  return (
    <div className="group relative overflow-hidden rounded-2xl bg-white dark:bg-secondary-800 border border-secondary-200 dark:border-secondary-700 shadow-lg hover:shadow-xl transition-all duration-300 hover:-translate-y-1">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br opacity-5 rounded-full blur-2xl group-hover:opacity-10 transition-opacity"
        style={{
          background: `linear-gradient(135deg, ${colorClasses.bg.replace('from-', '').replace(' to-', ', ')})`,
          transform: 'translate(30%, -30%)'
        }}
      />

      <div className="relative p-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-4">
            <div className={`w-14 h-14 bg-gradient-to-br ${colorClasses.bg} rounded-xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform duration-300`}>
              <Icon className="w-7 h-7 text-white" />
            </div>
            <div>
              <p className="text-sm font-medium text-secondary-500 dark:text-secondary-400">{title}</p>
              {subtitle && (
                <p className="text-xs text-secondary-400 dark:text-secondary-500">{subtitle}</p>
              )}
            </div>
          </div>

          {trend && (
            <div className="flex items-center gap-1 px-2 py-1 bg-secondary-100 dark:bg-secondary-700 rounded-lg">
              {getTrendIcon()}
              <span className={`text-sm font-medium ${colorClasses.text}`}>
                {trendValue}
              </span>
            </div>
          )}
        </div>

        <div className="flex items-baseline gap-2">
          <h3 className="text-3xl font-bold text-secondary-800 dark:text-secondary-200">
            {value}
          </h3>
          {typeof value === 'number' && (
            <span className="text-sm text-secondary-500 dark:text-secondary-400">
              {value === 1 ? 'item' : 'items'}
            </span>
          )}
        </div>
      </div>
    </div>
  );
};

export default StatCard;
